async function main() {
  // create fastify server instance
  const app = fastify();

  // initialize typeorm connection
  const connection = await createConnection();

  // register fastify-resty typeorm bootstraper
  app.register(typeorm, { connection });

  // bootstrap fastify-resty controllers using autoloader
  app.register(bootstrap, { entry: path.resolve(__dirname, 'api') });

  // start server listen on port 8080
  app.listen(8080, (err, address) => {
    if (err) {
      console.error(err);
      process.exit(1);
    }

    console.log(`Server is listening on ${address}`);
    console.log(app.printRoutes());
  });
}

export async function scanFolders(
  fastify: FastifyInstance,
  baseDir: string,
  current: string,
  prefix: string
): Promise<void> {
  const combined: string = path.join(baseDir, current);
  const combinedStat: fs.Stats = fs.statSync(combined);

  if (combinedStat.isDirectory()) {
    if (!path.basename(current).startsWith("_")) {
      for (const entry of fs.readdirSync(combined)) {
        await scanFolders(fastify, baseDir, path.join(current, entry), prefix);
      }
    }
  } else if (isAcceptableFile(combined, combinedStat)) {
    await autoload(fastify, combined, transformPathToUrl(current), prefix);
  }
}

public async handle() {
  // Is this email address already registered?
  let user = await this.fastify.resources.users.repositories.userRepository.findByEmail(this.request.body.email);
  if (user) {
    return this.reply.conflict(`User by the email address '${this.request.body.email}' already exists.`);
  }
  // Nope, then create them...
  user = await this.fastify.resources.users.repositories.userRepository.create({
    email: this.request.body.email,
    name: this.request.body.name,
  });
  // Done!
  return this.reply.code(201).send(user);
}

