insertPlaceholder(file: Pick<File, 'fieldname' | 'originalname' | 'encoding' | 'mimetype'>) {
  const placeholder = {
    fieldname: file.fieldname,
  }

  switch (this.strategy) {
    case 'NONE':
      break
    case 'VALUE':
      break
    case 'ARRAY':
      ;(this.request.files as Partial<File>[]).push(placeholder)
      break
    case 'OBJECT':
      if ((this.request.files as FilesObject)[file.fieldname]) {
        ;(this.request.files as FilesObject)[file.fieldname].push(placeholder)
      } else {
        ;(this.request.files as FilesObject)[file.fieldname] = [placeholder]
      }
      break
  }

  return placeholder
}

async #getSubprocessWorkerHealth (worker, options) {
  // Bound the ITC call so a hung child cannot freeze the health loop.
  // On timeout we fall back to last-known ELU with a null heap reading so
  // that the loop keeps rescheduling and signals remain observable.
  const result = await executeWithTimeout(sendViaITC(worker, 'getHealth'), kHealthITCTimeoutMs, kTimeout)

  if (result === kTimeout) {
    const previousELU = options.previousELU ?? worker.performance.eventLoopUtilization()
    return { elu: 1, heapUsed: null, heapTotal: null, currentELU: previousELU }
  }

  const { currentELU, heapUsed, heapTotal } = result
  const previousELU = options.previousELU
  let elu = currentELU
  if (previousELU) {
    elu = performance.eventLoopUtilization(currentELU, previousELU)
  }

  return { elu: elu.utilization, heapUsed, heapTotal, currentELU }
}

#updateDispatcher () {
  const telemetryConfig = this.#context.telemetryConfig
  const telemetryId = telemetryConfig?.applicationName

  const interceptor = dispatch => {
    return function InterceptedDispatch (opts, handler) {
      if (telemetryId) {
        opts.headers = {
          ...opts.headers,
          'x-plt-telemetry-id': telemetryId
        }
      }
      return dispatch(opts, handler)
    }
  }

  const dispatcher = getGlobalDispatcher().compose(interceptor)

  markAsPlatformaticDispatcher(dispatcher)
  setGlobalDispatcher(dispatcher)
  mirrorGlobalDispatcherForBuiltinFetch(dispatcher)
}

async #handleNotification (messageEvent) {
  let request
  try {
    request = parseRequest(messageEvent.data)
  } catch (err) {
    this.#logger.error({ err: ensureLoggableError(err) }, 'Failed to parse the notification message.')
    return
  }

  try {
    const handler = this.getHandler(request.name)
    if (!handler) {
      throw new errors.HandlerNotFoundError(request.name)
    }

    await handler(request.data, { application: this.#id, message: request, notification: true })
  } catch (error) {
    this.#logger.error({ error }, `"Handler for the "${request.name}" message failed.`)
  }
}

public authenticate<StrategyOrStrategies extends string | Strategy | (string | Strategy)[]>(
  strategyOrStrategies: StrategyOrStrategies,
  optionsOrCallback?: AuthenticateOptions | AuthenticateCallback<StrategyOrStrategies>,
  callback?: AuthenticateCallback<StrategyOrStrategies>
): RouteHandlerMethod {
  let options: AuthenticateOptions | undefined
  if (typeof optionsOrCallback === 'function') {
    options = {}
    callback = optionsOrCallback
  } else {
    options = optionsOrCallback
  }

  return new AuthenticationRoute(this, strategyOrStrategies, options, callback).handler
}

function getVerifier (options, globalOptions) {
  const useGlobalOptions = globalOptions ?? options === verifierConfig.options
  // Use global verifier if using global options with static key
  if (useGlobalOptions && hasStaticPublicKey) return verifier
  // Only cache verifier when using default options (except for key)
  if (useGlobalOptions && options.key && typeof options.key === 'string') {
    let verifier = validatorCache.get(options.key)
    if (!verifier) {
      verifier = createVerifier(options)
      validatorCache.set(options.key, verifier)
    }
    return verifier
  }
  return createVerifier(options)
}

function sign (payload, options, callback) {
  assert(payload, 'missing payload')
  // if a global signer was not created, sign mode is not supported
  assert(signer, 'unable to sign: secret is configured in verify mode')

  let localSigner = signer

  const localOptions = convertTemporalProps(options)
  const signerConfig = checkAndMergeSignOptions(localOptions, callback)

  if (options && typeof options !== 'function') {
    localSigner = createSigner(signerConfig.options)
  }

  if (typeof signerConfig.callback === 'function') {
    const token = localSigner(payload)
    signerConfig.callback(null, token)
  } else {
    return localSigner(payload)
  }
}

function getPluginName (func) {
  const display = getDisplayName(func)
  if (display) {
    return display
  }

  // let's see if this is a file, and in that case use that
  // this is common for plugins
  const cache = require.cache
  // cache is undefined inside SEA
  if (cache) {
    const keys = Object.keys(cache)

    for (let i = 0; i < keys.length; i++) {
      const key = keys[i]
      if (cache[key].exports === func) {
        return key
      }
    }
  }

  // if not maybe it's a named function, so use that
  if (func.name) {
    return func.name
  }

  return null
}

