function mergeLocations (context, mergedSchemaId, mergedLocations) {
  for (let i = 0, mergedLocationsLength = mergedLocations.length; i < mergedLocationsLength; i++) {
    const location = mergedLocations[i]
    const schema = location.schema
    if (schema.$ref) {
      mergedLocations[i] = resolveRef(context, location)
    }
  }

  const mergedSchemas = []
  for (const location of mergedLocations) {
    const schema = cloneOriginSchema(context, location.schema, location.schemaId)
    delete schema.$id

    mergedSchemas.push(schema)
  }

  const mergedSchema = mergeSchemas(mergedSchemas)
  const mergedLocation = new Location(mergedSchema, mergedSchemaId)

  context.refResolver.addSchema(mergedSchema, mergedSchemaId)
  return mergedLocation
}

function checkAndMergeOptions (options, defaultOptions, usePrivateKey, callback) {
  if (typeof options === 'function') {
    return { options: mergeOptionsWithKey(defaultOptions, usePrivateKey), callback: options }
  }

  return { options: mergeOptionsWithKey(options || defaultOptions, usePrivateKey), callback }
}

function checkAndMergeSignOptions (options, callback) {
  return checkAndMergeOptions(options, signOptions, true, callback)
}

function checkAndMergeVerifyOptions (options, callback) {
  return checkAndMergeOptions(options, verifyOptions, false, callback)
}

function schemaToMedia (schema) {
  const media = { schema }

  if (schema.examples?.length === 1) {
    media.example = schema.examples[0]
    delete schema.examples
  } else if (schema.examples?.length > 1) {
    media.examples = convertExamplesArrayToObject(schema.examples)
    // examples is invalid property of media object schema
    delete schema.examples
  }

  if (schema[xExamples]) {
    media.examples = schema[xExamples]
    delete schema[xExamples]
  }

  return media
}

function schemaToMediaRecursive (schema) {
  const media = schemaToMedia(schema)
  resolveSchemaExamplesRecursive(schema)
  return media
}

function mergeDependencies (keyword, values, mergedSchema) {
  const mergedDependencies = {}
  for (const dependencies of values) {
    for (const propertyName of Object.keys(dependencies)) {
      if (mergedDependencies[propertyName] === undefined) {
        mergedDependencies[propertyName] = []
      }
      const mergedPropertyDependencies = mergedDependencies[propertyName]
      for (const propertyDependency of dependencies[propertyName]) {
        if (!mergedPropertyDependencies.includes(propertyDependency)) {
          mergedPropertyDependencies.push(propertyDependency)
        }
      }
    }
  }
  mergedSchema[keyword] = mergedDependencies
}

function patchLogging () {
  disablePinoDirectWrite()

  const kFormatForStderr = getPrivateSymbol(console, 'kFormatForStderr')

  // To avoid out of order printing on the main thread, instruct console to only print to the stdout.
  console._stderr = console._stdout
  console._stderrErrorHandler = console._stdoutErrorHandler

  // To recognize stderr in the main thread, each line is prepended with a special private Unicode character.
  const originalFormatter = console[kFormatForStderr]
  console[kFormatForStderr] = function (args) {
    let string = kStderrMarker + originalFormatter(args).replaceAll('\n', '\n' + kStderrMarker)

    if (string.endsWith(kStderrMarker)) {
      string = string.slice(0, -1)
    }

    return string
  }
}

async #setDispatcher (undiciConfig) {
  const config = this.#config

  const dispatcherOpts = { ...undiciConfig }
  const interceptors = [this.#meshInterceptor]

  if (config.httpCache) {
    this.#sharedHttpCache = await createSharedStore(this.#root, config.httpCache)
    interceptors.push(
      undiciInterceptors.cache({
        store: this.#sharedHttpCache,
        methods: config.httpCache.methods ?? ['GET', 'HEAD'],
        origins: parseOrigins(config.httpCache.origins),
        cacheByDefault: config.httpCache.cacheByDefault,
        type: config.httpCache.type
      })
    )
  }
  this.#dispatcher = new Agent(dispatcherOpts).compose(interceptors)
}

async function startWebServer(): Promise<AddressInfo> {
  // ️️️✅ Best Practice: Declare a strict configuration schema and fail fast if the configuration is invalid
  configurationProvider.initializeAndValidate(configurationSchema);
  logger.configureLogger(
    {
      prettyPrint: Boolean(
        configurationProvider.getValue('logger.prettyPrint')
      ),
    },
    true
  );
  const expressApp = express();
  defineCommonMiddlewares(expressApp);
  defineRoutes(expressApp);
  defineErrorHandlingMiddleware(expressApp);
  const APIAddress = await openConnection(expressApp);
  return APIAddress;
}

function ensureMetadata<T extends object>(target: T): asserts target is T & { [Symbol.metadata]: Record<symbol, unknown> } {
  // @ts-expect-error no types for Symbol.metadata yet
  if (!Object.prototype.hasOwnProperty.call(target, Symbol.metadata)) {
    const metadata = {};
    // @ts-expect-error no types for Symbol.metadata yet
    if (Symbol.metadata in target) {
      // @ts-expect-error no types for Symbol.metadata yet
      const parentMetadata = target[Symbol.metadata] as Record<PropertyKey, unknown>;
      Object.setPrototypeOf(metadata, parentMetadata);
    }
    // @ts-expect-error no types for Symbol.metadata yet
    Reflect.defineProperty(target, Symbol.metadata, {
      value: metadata,
      enumerable: false,
      configurable: true,
      writable: false,
    });
  }
}
